&IsFuncoesSuporte = false If &TipoPerfil = 3 &IsFuncoesSuporte = true EndIF
For Each Order EmpCod, RotSts, MenOrd, MenNom, SubMenOrd, SubMenNom, RotOrd, RotNom Where EmpCod = &EmpCod Where RotSts = Status_AtivoInativo.ATIVO Where not RotLin.IsEmpty()
If not RotAutCod.IsEmpty() RetornaAutorizacao.Call(RotAutCod.Trim(), Status_SimNao.Nao, 1, &AutNiv) Else &AutNiv = 1 EndIF
If (&AutNiv > 0 and &AutNiv >= RotNivReq and RotNivReq < 4) or &AutNiv = 4 If &OldMenCod <> MenCod if &OldMenCod <> 0 &DVelop_MenuItem.subItems.Add(&DVelop_MenuSubRotina) &DVelop_Menu.Add(&DVelop_MenuItem) EndIf
&DVelop_MenuItem = new() &DVelop_MenuItem.id = 'M' + trim(str(MenCod)) &DVelop_MenuItem.caption = MenNom //&DVelop_MenuItem.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuItem.link = '' EndIF
if &IsFuncoesSuporte = true and UPPER(MenNom) = 'MISCELÂNEA' &IsFuncoesSuporte = false do 'suporte.jaspi' EndIF
If &OldMenCod <> MenCod or &OldSubMenCod <> SubMenCod if &OldSubMenCod <> 0 and &OldMenCod = MenCod //&DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina) &DVelop_MenuItem.subItems.Add(&DVelop_MenuSubRotina) Endif
&DVelop_MenuSubRotina = new() &DVelop_MenuSubRotina.id = 'M' + trim(str(MenCod)) + 'S' + trim(str(SubMenCod)) &DVelop_MenuSubRotina.caption = SubMenNom //&DVelop_MenuSubRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.link = '' EndIF
&DVelop_MenuRotina = new() &DVelop_MenuRotina.id = trim(Str(RotCod)) &DVelop_MenuRotina.caption = RotNom &DVelop_MenuRotina.link = RotLin //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks"
&DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
&IsFechaSubMenu = true &IsFechaMenu = true
&OldSubMenCod = SubMenCod &OldMenCod = MenCod EndIF EndFor
&DVelop_MenuItem.subItems.Add(&DVelop_MenuSubRotina) &DVelop_Menu.Add(&DVelop_MenuItem)
&WebSession.Set('aspx.AUTORIZACAOv3.JDF', &DVelop_Menu.ToXml())
sub 'suporte.jaspi'
&DVelop_MenuSubRotina = new() &DVelop_MenuSubRotina.id = 'supjaspi' &DVelop_MenuSubRotina.caption = 'suporte.jaspi' //&DVelop_MenuSubRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.link = ''
