//Politicas de segurança &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup9' &DVelop_MenuRotina.caption = 'Politica de Segurança' &DVelop_MenuRotina.link = 'gamwwsecuritypolicy.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//POS IMPORTACAO &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup2' &DVelop_MenuRotina.caption = 'Rotina Pós Importação' &DVelop_MenuRotina.link = 'wpPosImportacao.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//INSTANCIAS &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup10' &DVelop_MenuRotina.caption = 'Monitora Instâncias' &DVelop_MenuRotina.link = 'wwInstancias.aspx' //no start verifica old_perfil <> 3 vai para dashboard //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//Syncroniza &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup3' &DVelop_MenuRotina.caption = 'Rotina Syncronização' &DVelop_MenuRotina.link = 'wpsyncronizatudo.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//USUARIOS SUPORTES &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup5' &DVelop_MenuRotina.caption = 'Usuários Suporte' &DVelop_MenuRotina.link = 'wpsuporte.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
