//IMPORTACAO &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup6' &DVelop_MenuRotina.caption = 'x - Importar Produtos' &DVelop_MenuRotina.link = 'impProdutoXls.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//IMPORTACAO &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup8' &DVelop_MenuRotina.caption = 'x - Importar Clientes' &DVelop_MenuRotina.link = 'ImportaClienteXls.aspx' //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
//PARAMETROS &DVelop_MenuRotina = new() &DVelop_MenuRotina.id = 'Sup7' &DVelop_MenuRotina.caption = 'Monitora Notas Digitação' &DVelop_MenuRotina.link = 'monitoranotassuporte.aspx' //no start verifica old_perfil <> 3 vai para dashboard //&DVelop_MenuRotina.iconClass = "menu-icon fa fa-tasks" &DVelop_MenuSubRotina.subItems.Add(&DVelop_MenuRotina)
&DVelop_MenuItem.subItems.Add(&DVelop_MenuSubRotina) EndSub
